import type React from 'react';
import { createContextHook } from '@universe-design/react-utilities';
import type { UsePopperSharedReturnType } from './usePopper';
import type { UsePopperActionSharedReturnType } from './usePopperAction';

export interface PopperContextType extends UsePopperSharedReturnType, UsePopperActionSharedReturnType {
  /**
   * popper 是否打开的受控值
   */
  visible: boolean;
  disabled: boolean;
  rootPrefixCls: string;
  inlineElementMousePositionRef: React.MutableRefObject<{
    x: number;
    y: number;
  }>;
}

export const { Provider: PopperContextProvider, useContext: usePopperContext } = createContextHook<PopperContextType>(
  'PopperContext',
  {
    strict: true,
  },
);
